'use client';

import { useState } from 'react';
import { Check, Link } from 'lucide-react';
import { cn } from '@/lib/utils';

interface CopyButtonProps {
  url: string;
  className?: string;
}

export function CopyButton({ url, className }: CopyButtonProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(url);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback for older browsers
      const input = document.createElement('input');
      input.value = url;
      document.body.appendChild(input);
      input.select();
      document.execCommand('copy');
      document.body.removeChild(input);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={cn(
        'flex items-center gap-2 rounded-lg border border-white/10 bg-white/5 px-3 py-1.5',
        'text-sm text-gray-300 transition-colors hover:border-white/20 hover:text-white',
        className
      )}
      aria-label="Copy profile link"
    >
      {copied ? (
        <>
          <Check className="h-3.5 w-3.5 text-green-400" />
          <span>Copied!</span>
        </>
      ) : (
        <>
          <Link className="h-3.5 w-3.5" />
          <span>Copy link</span>
        </>
      )}
    </button>
  );
}

