import { format, subDays } from 'date-fns';
import type { HeatmapEntry } from '@/types/profile';

interface ContributionHeatmapProps {
  data: HeatmapEntry[];
  totalContributions: number;
}

const NIVO_COLORS = ['#0e4429', '#006d32', '#26a641', '#39d353'];

export function ContributionHeatmap({ data, totalContributions }: ContributionHeatmapProps) {
  const today = format(new Date(), 'yyyy-MM-dd');
  const yearAgo = format(subDays(new Date(), 364), 'yyyy-MM-dd');

  if (data.length === 0) {
    return (
      <div className="flex h-[160px] items-center justify-center text-sm text-gray-500">
        No contribution data available
      </div>
    );
  }

  return (
    <div>
      <p className="mb-3 text-sm text-gray-400">
        <span className="font-semibold text-white">{totalContributions.toLocaleString()}</span>{' '}
        contributions in the last year
      </p>
      <div style={{ height: '160px' }}>
        <ResponsiveCalendar
          data={data}
          from={yearAgo}
          to={today}
          emptyColor="#161b22"
          colors={NIVO_COLORS}
          margin={{ top: 20, right: 0, bottom: 0, left: 24 }}
          yearSpacing={40}
          monthBorderColor="#0d1117"
          dayBorderWidth={2}
          dayBorderColor="#0d1117"
          theme={{
            text: { fill: '#8b949e', fontSize: 11 },
            tooltip: {
              container: {
                background: '#1c2128',
                color: '#e6edf3',
                borderRadius: '6px',
                border: '1px solid rgba(255,255,255,0.1)',
                fontSize: 12,
              },
            },
          }}
          tooltip={({ day, value }) => (
            <div className="rounded px-2 py-1 text-xs">
              {Number(value)} contributions on {day}
            </div>
          )}
        />
      </div>
    </div>
  );
}

